blocks.body:
{
    "level": "A1–B1",
    "intro": "W tym temacie nauczysz się tworzyć <strong>pytania specjalne („Wh-questions”)</strong>, czyli pytania o konkretną informację.",
    "rules": [
        {
            "label": "WHO / WHAT",
            "color": "emerald",
            "text": "<strong>Who</strong> pytamy o osoby, a <strong>what</strong> o rzeczy i informacje:",
            "example": "Who called you? / What do you want?"
        },
        {
            "label": "WHERE / WHEN",
            "color": "blue",
            "text": "<strong>Where</strong> dotyczy miejsca, a <strong>when</strong> czasu:",
            "example": "Where do you live? / When did it happen?"
        },
        {
            "label": "WHY / HOW",
            "color": "amber",
            "text": "<strong>Why</strong> pyta o powód, a <strong>how</strong> o sposób, stan lub stopień:",
            "example": "Why are you late? / How does it work?"
        }
    ]
}

{
    "title": "1. Co to są pytania Wh?",
    "intro": "Pytania Wh wymagają bardziej szczegółowej odpowiedzi niż pytania tak/nie:",
    "items": [
        {
            "label": "Pytanie ogólne",
            "title": "Do you like tea?",
            "subtitle": "Odpowiedź: Yes / No"
        },
        {
            "label": "Pytanie specjalne",
            "title": "What do you like?",
            "subtitle": "Odpowiedź: I like tea."
        },
        {
            "label": "Struktura",
            "title": "Wh-word + auxiliary + subject + verb",
            "subtitle": "Słowo pytające zwykle stoi na początku zdania"
        }
    ]
}

{
    "title": "2. WHO — kto?",
    "sections": [
        {
            "label": "Who jako pytanie o osobę",
            "color": "emerald",
            "description": "<strong>Who</strong> używamy, gdy pytamy o osobę jako dopełnienie albo partnera czynności.",
            "examples": [
                {
                    "en": "Who do you love?",
                    "ua": "Kogo kochasz?"
                },
                {
                    "en": "Who did you see?",
                    "ua": "Kogo widziałeś?"
                },
                {
                    "en": "Who are you talking to?",
                    "ua": "Z kim rozmawiasz?"
                },
                {
                    "en": "Who does she work for?",
                    "ua": "Dla kogo ona pracuje?"
                }
            ]
        },
        {
            "label": "Who jako pytanie o podmiot",
            "color": "sky",
            "description": "Gdy <strong>who</strong> jest podmiotem, nie używamy <strong>do/does/did</strong>.",
            "examples": [
                {
                    "en": "Who lives here?",
                    "ua": "Kto tu mieszka?"
                },
                {
                    "en": "Who called you?",
                    "ua": "Kto do ciebie dzwonił?"
                },
                {
                    "en": "Who wants coffee?",
                    "ua": "Kto chce kawy?"
                },
                {
                    "en": "Who knows the answer?",
                    "ua": "Kto zna odpowiedź?"
                }
            ]
        },
        {
            "label": "Who w różnych czasach",
            "color": "purple",
            "description": "<strong>Who</strong> może pojawiać się w różnych czasach i konstrukcjach.",
            "examples": [
                {
                    "en": "Who will come to the party?",
                    "ua": "Kto przyjdzie na imprezę?"
                },
                {
                    "en": "Who has finished the work?",
                    "ua": "Kto skończył pracę?"
                },
                {
                    "en": "Who can help me?",
                    "ua": "Kto może mi pomóc?"
                }
            ],
            "note": "📌 Jeśli <strong>who</strong> jest podmiotem, po nim od razu pojawia się czasownik."
        }
    ]
}

{
    "title": "3. WHAT — co?",
    "sections": [
        {
            "label": "What jako pytanie o informację",
            "color": "blue",
            "description": "<strong>What</strong> służy do pytania o rzeczy, działania i informacje.",
            "examples": [
                {
                    "en": "What do you want?",
                    "ua": "Czego chcesz?"
                },
                {
                    "en": "What did she say?",
                    "ua": "Co ona powiedziała?"
                },
                {
                    "en": "What are you doing?",
                    "ua": "Co robisz?"
                },
                {
                    "en": "What is your name?",
                    "ua": "Jak masz na imię?"
                }
            ]
        },
        {
            "label": "What + rzeczownik",
            "color": "amber",
            "description": "<strong>What</strong> może też stać przed rzeczownikiem, gdy doprecyzowujemy pytanie.",
            "examples": [
                {
                    "en": "What colour is it?",
                    "ua": "Jaki to kolor?"
                },
                {
                    "en": "What time is it?",
                    "ua": "Która jest godzina?"
                },
                {
                    "en": "What music do you like?",
                    "ua": "Jaką muzykę lubisz?"
                },
                {
                    "en": "What size do you need?",
                    "ua": "Jaki rozmiar potrzebujesz?"
                }
            ]
        },
        {
            "label": "What jako pytanie o podmiot",
            "color": "rose",
            "description": "Gdy <strong>what</strong> jest podmiotem, również nie używamy <strong>do/does/did</strong>.",
            "examples": [
                {
                    "en": "What happened?",
                    "ua": "Co się stało?"
                },
                {
                    "en": "What makes you happy?",
                    "ua": "Co cię uszczęśliwia?"
                },
                {
                    "en": "What caused the problem?",
                    "ua": "Co spowodowało problem?"
                }
            ],
            "note": "📌 <strong>What happened?</strong> jest poprawne, ale <span class=\"line-through\">What did happen?</span> nie pasuje do neutralnego pytania o podmiot."
        }
    ]
}

{
    "title": "4. WHERE — gdzie?",
    "sections": [
        {
            "label": "Where jako pytanie o miejsce",
            "color": "emerald",
            "description": "<strong>Where</strong> używamy, gdy pytamy o miejsce albo kierunek.",
            "examples": [
                {
                    "en": "Where do you live?",
                    "ua": "Gdzie mieszkasz?"
                },
                {
                    "en": "Where are you going?",
                    "ua": "Dokąd idziesz?"
                },
                {
                    "en": "Where did you buy it?",
                    "ua": "Gdzie to kupiłeś?"
                },
                {
                    "en": "Where is the bank?",
                    "ua": "Gdzie jest bank?"
                }
            ]
        },
        {
            "label": "Where z dodatkowymi informacjami",
            "color": "sky",
            "description": "Pytania z <strong>where</strong> często łączą się z przyimkami i dodatkowymi określeniami miejsca.",
            "examples": [
                {
                    "en": "Where are you from?",
                    "ua": "Skąd jesteś?"
                },
                {
                    "en": "Where are they staying?",
                    "ua": "Gdzie oni się zatrzymali?"
                },
                {
                    "en": "Where did she come from?",
                    "ua": "Skąd ona przyszła?"
                }
            ],
            "note": "📌 Struktura jest taka sama jak w innych pytaniach Wh: <strong>where + auxiliary + subject + verb</strong>."
        }
    ]
}

{
    "title": "5. WHEN — kiedy?",
    "sections": [
        {
            "label": "When jako pytanie o czas",
            "color": "blue",
            "description": "<strong>When</strong> służy do pytania o moment, datę albo porę.",
            "examples": [
                {
                    "en": "When do you wake up?",
                    "ua": "Kiedy się budzisz?"
                },
                {
                    "en": "When did it happen?",
                    "ua": "Kiedy to się stało?"
                },
                {
                    "en": "When are you leaving?",
                    "ua": "Kiedy wyjeżdżasz?"
                },
                {
                    "en": "When will you come back?",
                    "ua": "Kiedy wrócisz?"
                }
            ]
        },
        {
            "label": "When w różnych czasach",
            "color": "purple",
            "description": "<strong>When</strong> działa z każdym czasem, jeśli pytamy o czas zdarzenia.",
            "examples": [
                {
                    "en": "When is your birthday?",
                    "ua": "Kiedy masz urodziny?"
                },
                {
                    "en": "When does the meeting start?",
                    "ua": "Kiedy zaczyna się spotkanie?"
                },
                {
                    "en": "When were you there?",
                    "ua": "Kiedy tam byłeś?"
                }
            ],
            "note": "📌 Odpowiedź może być bardzo konkretna (<em>at 5 pm</em>) albo bardziej ogólna (<em>tomorrow</em>, <em>last week</em>)."
        }
    ]
}

{
    "title": "6. WHY — dlaczego?",
    "sections": [
        {
            "label": "Why jako pytanie o powód",
            "color": "amber",
            "description": "<strong>Why</strong> używamy, gdy pytamy o przyczynę albo motywację.",
            "examples": [
                {
                    "en": "Why are you sad?",
                    "ua": "Dlaczego jesteś smutny?"
                },
                {
                    "en": "Why did she leave?",
                    "ua": "Dlaczego ona wyszła?"
                },
                {
                    "en": "Why are you learning English?",
                    "ua": "Dlaczego uczysz się angielskiego?"
                },
                {
                    "en": "Why is it important?",
                    "ua": "Dlaczego to jest ważne?"
                }
            ]
        },
        {
            "label": "Odpowiedź z because",
            "color": "rose",
            "description": "Na pytanie z <strong>why</strong> często odpowiadamy, używając <strong>because</strong>.",
            "examples": [
                {
                    "en": "Why are you late? — Because I missed the bus.",
                    "ua": "Dlaczego się spóźniłeś? — Bo uciekł mi autobus."
                },
                {
                    "en": "Why is she upset? — Because he forgot her birthday.",
                    "ua": "Dlaczego ona jest zdenerwowana? — Bo on zapomniał o jej urodzinach."
                }
            ]
        },
        {
            "label": "Sugestie z why don't",
            "color": "emerald",
            "description": "Konstrukcja <strong>Why don't...?</strong> często brzmi jak sugestia albo propozycja.",
            "examples": [
                {
                    "en": "Why don't we go to the cinema?",
                    "ua": "Może pójdziemy do kina?"
                },
                {
                    "en": "Why don't you ask him?",
                    "ua": "Może go zapytasz?"
                }
            ],
            "note": "📌 To nie tylko pytanie o powód, ale często też uprzejma propozycja."
        },
        {
            "label": "Why z modalnymi",
            "color": "purple",
            "description": "<strong>Why</strong> może też łączyć się z czasownikami modalnymi.",
            "examples": [
                {
                    "en": "Why should I believe you?",
                    "ua": "Dlaczego miałbym ci uwierzyć?"
                },
                {
                    "en": "Why would she do that?",
                    "ua": "Dlaczego ona miałaby to zrobić?"
                },
                {
                    "en": "Why can't we stay longer?",
                    "ua": "Dlaczego nie możemy zostać dłużej?"
                },
                {
                    "en": "Why must you leave now?",
                    "ua": "Dlaczego musisz teraz wyjść?"
                }
            ],
            "note": "📌 Struktura: <strong>why + modal + subject + verb</strong>."
        }
    ]
}

{
    "title": "7. HOW — jak?",
    "sections": [
        {
            "label": "How jako pytanie o sposób lub stan",
            "color": "blue",
            "description": "<strong>How</strong> pyta o sposób wykonania czegoś, przebieg albo stan.",
            "examples": [
                {
                    "en": "How do you go to work?",
                    "ua": "Jak dojeżdżasz do pracy?"
                },
                {
                    "en": "How does it work?",
                    "ua": "Jak to działa?"
                },
                {
                    "en": "How are you?",
                    "ua": "Jak się masz?"
                },
                {
                    "en": "How did you learn English?",
                    "ua": "Jak nauczyłeś się angielskiego?"
                }
            ]
        },
        {
            "label": "How + adjective/adverb",
            "color": "purple",
            "description": "<strong>How</strong> łączy się też z przymiotnikami i przysłówkami.",
            "examples": [
                {
                    "en": "How old are you?",
                    "ua": "Ile masz lat?"
                },
                {
                    "en": "How tall is he?",
                    "ua": "Jakiego jest wzrostu?"
                },
                {
                    "en": "How far is the station?",
                    "ua": "Jak daleko jest stacja?"
                },
                {
                    "en": "How long does it take?",
                    "ua": "Jak długo to trwa?"
                }
            ]
        },
        {
            "label": "How much / how many",
            "color": "emerald",
            "description": "<strong>How much</strong> pytamy o ilość niepoliczalną albo cenę, a <strong>how many</strong> o liczbę rzeczy policzalnych.",
            "examples": [
                {
                    "en": "How much is it?",
                    "ua": "Ile to kosztuje?"
                },
                {
                    "en": "How many books do you have?",
                    "ua": "Ile masz książek?"
                },
                {
                    "en": "How much time do we have?",
                    "ua": "Ile mamy czasu?"
                },
                {
                    "en": "How many people are coming?",
                    "ua": "Ile osób przyjdzie?"
                }
            ],
            "note": "📌 <strong>Much</strong> łączy się z rzeczownikami niepoliczalnymi, a <strong>many</strong> z policzalnymi."
        }
    ]
}

{
    "title": "8. Tabela słów pytających",
    "intro": "Najważniejsze słowa pytające i ich funkcje:",
    "rows": [
        {
            "en": "WHO",
            "ua": "kto / kogo / z kim",
            "note": "Pytamy o osoby: Who called? / Who did you see?"
        },
        {
            "en": "WHAT",
            "ua": "co / jaki",
            "note": "Pytamy o rzeczy i informacje: What do you want? / What time is it?"
        },
        {
            "en": "WHERE",
            "ua": "gdzie / dokąd / skąd",
            "note": "Pytamy o miejsce i kierunek: Where do you live?"
        },
        {
            "en": "WHEN",
            "ua": "kiedy",
            "note": "Pytamy o czas: When did it happen?"
        },
        {
            "en": "WHY",
            "ua": "dlaczego",
            "note": "Pytamy o powód: Why are you late?"
        },
        {
            "en": "HOW",
            "ua": "jak / ile / jak bardzo",
            "note": "Pytamy o sposób, stan i stopień: How does it work? / How old are you?"
        }
    ],
    "warning": "📌 Standardowa kolejność to zwykle <strong>Wh-word + auxiliary + subject + verb</strong>."
}

{
    "title": "9. Struktura pytań Wh",
    "sections": [
        {
            "label": "Struktura standardowa",
            "color": "emerald",
            "description": "W większości pytań Wh używamy takiego schematu:",
            "examples": [
                {
                    "en": "Wh-word + auxiliary + subject + main verb + ...?",
                    "ua": "Słowo pytające + czasownik pomocniczy + podmiot + czasownik główny + ...?"
                },
                {
                    "en": "What do you want?",
                    "ua": "Czego chcesz?"
                },
                {
                    "en": "Where did she go?",
                    "ua": "Dokąd ona poszła?"
                }
            ]
        },
        {
            "label": "Pytania o podmiot",
            "color": "sky",
            "description": "Gdy słowo pytające jest podmiotem, nie dodajemy <strong>do/does/did</strong>.",
            "examples": [
                {
                    "en": "Who lives here?",
                    "ua": "Kto tu mieszka?"
                },
                {
                    "en": "What happened?",
                    "ua": "Co się stało?"
                }
            ],
            "note": "📌 W pytaniu o podmiot po słowie pytającym od razu pojawia się czasownik."
        },
        {
            "label": "Z czasownikiem TO BE",
            "color": "amber",
            "description": "Z <strong>to be</strong> nie potrzebujemy <strong>do/does/did</strong>.",
            "examples": [
                {
                    "en": "Where are you?",
                    "ua": "Gdzie jesteś?"
                },
                {
                    "en": "Who is she?",
                    "ua": "Kim ona jest?"
                },
                {
                    "en": "What is your name?",
                    "ua": "Jak masz na imię?"
                }
            ],
            "note": "📌 Struktura: <strong>Wh-word + be + subject</strong>."
        }
    ]
}

{
    "title": "10. Typowe błędy",
    "items": [
        {
            "label": "Błąd 1",
            "color": "rose",
            "title": "Brak czasownika pomocniczego w zwykłym pytaniu Wh.",
            "wrong": "❌ What you want?",
            "right": "✅ <span class=\"font-mono\">What do you want?</span>"
        },
        {
            "label": "Błąd 2",
            "color": "amber",
            "title": "Dodawanie <strong>do/does</strong> w pytaniu o podmiot.",
            "wrong": "❌ Who does live here?",
            "right": "✅ <span class=\"font-mono\">Who lives here?</span>"
        },
        {
            "label": "Błąd 3",
            "color": "sky",
            "title": "Niepoprawna kolejność lub forma po <strong>did</strong>.",
            "wrong": "❌ Where she went?",
            "right": "✅ <span class=\"font-mono\">Where did she go?</span>"
        },
        {
            "label": "Błąd 4",
            "color": "purple",
            "title": "Mylenie <strong>how much</strong> i <strong>how many</strong>.",
            "wrong": "❌ How many money do you have?",
            "right": "✅ <span class=\"font-mono\">How much money do you have?</span>"
        }
    ]
}

{
    "title": "12. Ćwicz",
    "select_title": "Ćwiczenie 1. Wybierz właściwe słowo pytające",
    "select_intro": "Wybierz właściwe słowo pytające do każdego zdania.",
    "selects": [
        {
            "label": "_____ is your name? (What / Who / Where)",
            "prompt": "Które słowo pasuje najlepiej?"
        },
        {
            "label": "_____ do you live? (When / Where / Why)",
            "prompt": "Które słowo pasuje najlepiej?"
        },
        {
            "label": "_____ are you learning English? (How / Why / What)",
            "prompt": "Które słowo pasuje najlepiej?"
        },
        {
            "label": "_____ old are you? (What / Where / How)",
            "prompt": "Które słowo pasuje najlepiej?"
        }
    ],
    "options": [
        "a",
        "b",
        "c"
    ],
    "input_title": "Ćwiczenie 2. Ułóż pytanie",
    "input_intro": "Utwórz pytanie z podanym słowem pytającym.",
    "inputs": [
        {
            "before": "You live in Warsaw. (Where) → ",
            "after": ""
        },
        {
            "before": "She is 25. (How old) → ",
            "after": ""
        },
        {
            "before": "He went to the park. (Where) → ",
            "after": ""
        },
        {
            "before": "They arrived at 5 pm. (When) → ",
            "after": ""
        }
    ],
    "rephrase_title": "Ćwiczenie 3. Popraw błąd",
    "rephrase_intro": "Znajdź i popraw błąd w pytaniu specjalnym.",
    "rephrase": [
        {
            "example_label": "Przykład:",
            "example_original": "Where she lives?",
            "example_target": "Where does she live?"
        },
        {
            "original": "1. Who does live here?",
            "placeholder": "Napraw błąd"
        },
        {
            "original": "2. What you want?",
            "placeholder": "Napraw błąd"
        },
        {
            "original": "3. How many money do you need?",
            "placeholder": "Popraw błąd"
        }
    ]
}

